mapper.select:
select m.message_id, m.deceased_id, m.visitor_name, m.visitor_phone, m.relation, m.content, m.is_audited, m.ip_address, m.create_time, d.name as deceased_name from mem_message m left join mem_deceased d on m.deceased_id = d.deceased_id
and m.deceased_id = #{deceasedId}
and m.visitor_name like concat('%', #{visitorName}, '%')
and m.is_audited = #{isAudited}
order by m.create_time desc

mapper.update:
update mem_message
visitor_name = #{visitorName}, visitor_phone = #{visitorPhone}, relation = #{relation}, content = #{content}, is_audited = #{isAudited},
where message_id = #{messageId}

mapper.select:
select count(*) from mem_message m
left join mem_deceased d on m.deceased_id = d.deceased_id
where d.org_id = #{orgId}
